### Código de Jogo de Mario
Aqui está um exemplo simples de um jogo de Mario estilo Mario em HTML, com JavaScript e CSS embutidos. Este jogo é basicamente um jogo de plataforma onde Mario precisa atravessar o cenário sem tocar nos obstáculos.

```html
<!DOCTYPE html>
<html lang="pt-br">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Jogo de Mario</title>
    <style>
        #jogo {
            width: 800px;
            height: 600px;
            border: 1px solid black;
            position: relative;
        }

        #mario {
            width: 50px;
            height: 50px;
            background-color: red;
            position: absolute;
            top: 0px;
            left: 0px;
        }

        #obstaculo {
            width: 50px;
            height: 50px;
            background-color: blue;
            position: absolute;
            top: 200px;
            left: 300px;
        }

        #meta {
            width: 50px;
            height: 50px;
            background-color: green;
            position: absolute;
            top: 500px;
            left: 700px;
        }
    </style>
</head>
<body>
    <div id="jogo">
        <div id="mario"></div>
        <div id="obstaculo"></div>
        <div id="meta"></div>
    </div>
    <script>
        let mario = document.getElementById('mario');
        let obstaculo = document.getElementById('obstaculo');
        let meta = document.getElementById('meta');
        let velocidadex = 0;
        let velocidadey = 0;
        let gravidade = 0.2;
        let altura = 0;
        let largura = 0;

        document.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft') {
                velocidadex = -5;
            } else if (e.key === 'ArrowRight') {
                velocidadex = 5;
            } else if (e.key === 'ArrowUp') {
                velocidadey = -10;
            }
        });

        document.addEventListener('keyup', (e) => {
            if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
                velocidadex = 0;
            }
        });

        function atualizar() {
            altura += velocidadey;
            largura += velocidadex;

            velocidadey += gravidade;

            if (altura > 550) {
                altura = 550;
                velocidadey = 0;
            }

            if (largura < 0) {
                largura = 0;
            } else if (largura > 750) {
                largura = 750;
            }

            mario.style.top = `${altura}px`;
            mario.style.left = `${largura}px`;

            if (largura + 50 > obstaculo.offsetLeft && largura < obstaculo.offsetLeft + 50 && altura + 50 > obstaculo.offsetTop && altura < obstaculo.offsetTop + 50) {
                alert('Game Over!');
                window.location.reload();
            }

            if (largura + 50 > meta.offsetLeft && largura < meta.offsetLeft + 50 && altura + 50 > meta.offsetTop && altura < meta.offsetTop + 50) {
                alert('Parabéns! Você venceu!');
                window.location.reload();
            }

            requestAnimationFrame(atualizar);
        }

        atualizar();
    </script>
</body>
</html>
```

