**Código Completo de um Jogo de Site**
=====================================

**Jogo:** Snake Game
**Tecnologias:** HTML, CSS, JavaScript
**Descrição:** Um jogo clássico de snake em que o jogador controla uma cobra que come frutas e cresce.

**Código:**
```html
<!-- index.html -->
<!DOCTYPE html>
<html>
<head>
  <title>Snake Game</title>
  <link rel="stylesheet" href="style.css">
</head>
<body>
  <canvas id="game-canvas" width="400" height="400"></canvas>
  <script src="script.js"></script>
</body>
</html>
```

```css
/* style.css */
body {
  background-color: #f0f0f0;
}

#game-canvas {
  border: 1px solid #000;
}
```

```javascript
// script.js
const canvas = document.getElementById('game-canvas');
const ctx = canvas.getContext('2d');
const snake = [];
const food = {};
const direction = 'right';
let score = 0;

// Função para iniciar o jogo
function init() {
  snake.push({ x: 200, y: 200 });
  food.x = Math.floor(Math.random() * 400) / 20;
  food.y = Math.floor(Math.random() * 400) / 20;
  food.color = '#ff0000';
  draw();
  setInterval(update, 100);
}

// Função para atualizar o jogo
function update() {
  const head = snake[0];
  let newHead = { x: head.x, y: head.y };

  switch (direction) {
    case 'right':
      newHead.x += 20;
      break;
    case 'left':
      newHead.x -= 20;
      break;
    case 'up':
      newHead.y -= 20;
      break;
    case 'down':
      newHead.y += 20;
      break;
  }

  // Verifica se a cobra bateu na parede ou em si mesma
  if (newHead.x < 0 || newHead.x >= 400 || newHead.y < 0 || newHead.y >= 400 ||
      snake.some((part) => part.x === newHead.x && part.y === newHead.y)) {
    alert('Game Over!');
    init();
    return;
  }

  // Verifica se a cobra comeu a fruta
  if (newHead.x === food.x * 20 && newHead.y === food.y * 20) {
    score++;
    food.x = Math.floor(Math.random() * 400) / 20;
    food.y = Math.floor(Math.random() * 400) / 20;
    snake.push({ x: newHead.x, y: newHead.y });
  } else {
    snake.unshift(newHead);
    snake.pop();
  }

  draw();
}

// Função para desenhar o jogo
function draw() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  snake.forEach((part) => {
    ctx.fillStyle = '#00ff00';
    ctx.fillRect(part.x, part.y, 20, 20);
  });

  ctx.fillStyle = food.color;
  ctx.fillRect(food.x * 20, food.y * 20, 20, 20);

  ctx.fillStyle = '#fff';
  ctx.font = '24px Arial';
  ctx.textAlign = 'left';
  ctx.textBaseline = 'top';
  ctx.fillText(`Score: ${score}`, 10, 10);
}

// Função para lidar com os eventos de teclado
function handleKeyEvent(event) {
  switch (event.key) {
    case 'ArrowRight':
      direction = 'right';
      break;
    case 'ArrowLeft':
      direction = 'left';
      break;
    case 'ArrowUp':
      direction = 'up';
      break;
    case 'ArrowDown':
      direction = 'down';
      break;
  }
}

document.addEventListener('keydown', handleKeyEvent);
init();
```
**Explicação:**

* O jogo é criado usando um canvas e um contexto de desenho 2D.
* A cobra é representada por um array de objetos que contêm as coordenadas x e y de cada parte da cobra.
* A fruta é representada por um objeto que contém as coordenadas x e y da fruta.
* A direção da cobra é controlada pelo usuário usando as teclas de seta.
* O jogo é atualizado a cada 100 milissegundos usando a função `update`.
* A função `draw` é responsável por desenhar o jogo no canvas.
* A função `handleKeyEvent` lida com os eventos de teclado.

**Observação:**

